#!/bin/bash
# Deploy AI Visibility v3: location field, real logos, sector-aware queries
# Fixes: 1) Adds "Business Location" input to audit form
#        2) Replaces emoji icons with real AI platform logos
#        3) Uses sector-specific keywords in search queries
#        4) Shows "Holding Company Services — Seattle, WA" instead of "your area"
set -e
cd ~/chaos_tester

echo "=== AI Visibility v3 Deploy ==="

# 1. Patch config.py: add business_location field
echo "Patching config.py..."
if ! grep -q "business_location" config.py; then
  sed -i '/run_ai_visibility: bool = True/a\    business_location: str = ""           # optional user-provided city for AI queries' config.py
  echo "  Added business_location field"
else
  echo "  business_location already exists, skipping"
fi

# 2. Patch app.py: read business_location from form
echo "Patching app.py..."
if ! grep -q "business_location" app.py; then
  sed -i '/config\.seed_urls = \[/i\    config.business_location = _get("business_location", "").strip()' app.py
  echo "  Added business_location form reading"
else
  echo "  business_location reading already exists, skipping"
fi

# 3. Write modules/business_identifier.py
echo "Writing modules/business_identifier.py..."
base64 -d > modules/business_identifier.py << 'B64END'

B64END
# 4. Write modules/ai_visibility.py
echo "Writing modules/ai_visibility.py..."
base64 -d > modules/ai_visibility.py << 'B64END'

B64END
# 5. Write templates/report.html
echo "Writing templates/report.html..."
base64 -d > templates/report.html << 'B64END'

B64END
# 6. Write templates/dashboard.html
echo "Writing templates/dashboard.html..."
base64 -d > templates/dashboard.html << 'B64END'

B64END

echo ""
echo "All files written. Verifying..."
python3 -c "import ast; ast.parse(open('modules/business_identifier.py').read()); print('  business_identifier.py: OK')"
python3 -c "import ast; ast.parse(open('modules/ai_visibility.py').read()); print('  ai_visibility.py: OK')"
echo "  report.html: $(wc -l < templates/report.html) lines"
echo "  dashboard.html: $(wc -l < templates/dashboard.html) lines"
echo ""

# Git commit
echo "Committing..."
git add modules/business_identifier.py modules/ai_visibility.py templates/report.html templates/dashboard.html config.py app.py
git commit -m "feat: AI Visibility v3 — location input, real logos, sector queries

- Added Business Location input field to audit form
- User-provided location takes priority over auto-detection
- Multi-source location auto-detection: JSON-LD, HTML patterns,
  OpenCorporates, IRS EO, secondary pages, RDAP/WHOIS
- Replaced emoji icons with real AI platform logos (OpenAI, Perplexity,
  Anthropic, Google Gemini) via CDN
- Sector detection from IRS NTEE codes, business name analysis,
  Schema.org types, page content keywords
- 35+ sector-specific query keyword sets for targeted AI queries
"
git push origin main

# Deploy to Cloud Run
echo ""
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester --source . --region us-central1 --allow-unauthenticated --project chaos-tester

echo ""
echo "=== Deploy complete! ==="
echo "Test at: https://website-auditor.io"
echo "Enter 'Seattle, WA' in the Business Location field for kevinarmstrong.io"
